def _json_row_count(output: str) -> int:
    """Count top-level rows from the CLI's --format json response.

    JSON lists count as `len`. JSON dicts count as 1 (single-object
    responses like `calendar_open_today`). Non-JSON output (warnings,
    stderr noise) counts as 0.
    """
    try:
        parsed = json.loads(output.strip().splitlines()[-1]) \
            if output.strip() else None
    except (json.JSONDecodeError, IndexError):
        return 0
    if isinstance(parsed, list):
        return len(parsed)
    if isinstance(parsed, dict):
        return 1
    return 0

